import{_ as a,o as s,c as t,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"37. Higher Duties Allowance","description":"","frontmatter":{"title":"37. Higher Duties Allowance","eba":"Allied Health Professionals 2021-2026","topics":["allowances","wages","higher-duties"]},"headers":[],"relativePath":"ebas/allied-health/allowances/37-higher-duties-allowance.md","filePath":"ebas/allied-health/allowances/37-higher-duties-allowance.md"}'),r={name:"ebas/allied-health/allowances/37-higher-duties-allowance.md"};function o(n,e,l,h,p,d){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="_37-higher-duties-allowance" tabindex="-1">37. Higher Duties Allowance <a class="header-anchor" href="#_37-higher-duties-allowance" aria-label="Permalink to &quot;37. Higher Duties Allowance&quot;">​</a></h1><p>Note: An individual Employee does not need to perform the duties of the Absent Employee/Vacant Position for the entire period of the absence/vacancy in order to access the higher duties allowance.</p><p><strong>37.1</strong> An Employee (Relieving Employee) who is engaged in performing the duties of:</p><p><strong>(a)</strong> another employee (Absent Employee) on a higher classification who is absent for five (5) days or more; or</p><p><strong>(b)</strong> a position that is vacant (Vacant Position) that is at a higher classification that is vacant for five (5) days or more;</p><p>will receive the higher duties allowance in accordance with this clause 37.</p><p><strong>37.2</strong> The higher duties allowance will be paid as follows:</p><p><strong>(a)</strong> where the Absent Employee / Vacant Position is classified under this Agreement;</p><p><strong>(i)</strong> not less than the minimum rate prescribed for the classification applying to the Absent Employee/ Vacant Position; or</p><p><strong>(ii)</strong> for those classifications listed in subclause 37.5, where the Relieving Employee is at the top increment of their Grade/Level/Class, the rate set out in that subclause;</p><p><strong>(b)</strong> where the Absent Employee / Vacant Position is not classified under this Agreement but there is a classification under this Agreement which would apply to the work performed if the Absent Employee / Vacant Position was covered by this Agreement:</p><p><strong>(i)</strong> not less than the minimum rate prescribed for that equivalent classification under this Agreement; or</p><p><strong>(ii)</strong> for those classifications listed in subclause 37.5, where the Relieving Employee is at the top increment of their Grade/Level/Class, the rate set out in that subclause;</p><p><strong>(c)</strong> where the Absent Employee / Vacant Position is not classified under this Agreement and subclause 37.2(b) above does not apply, 10% of the Relieving Employee’s base rate; even where the period the Relieving Employee is required to assume the duties of the Absent Employee/Vacant Position is less than five (5) days.</p><p>Example 1 A Grade 3 Employee is absent for five (5) days. Two (2) Grade 2 Employees are engaged in performing the duties of the absent Grade 3 Employee, one for three (3) days and one for two (2) days. Each Grade 2 Employee would be entitled to the higher duties allowance. Example 2 A Grade 2 Employee has ceased their employment with the Employer. Until the position is filled, three (3) Grade 1 Employees are engaged in performing the duties of the vacant Grade 2 position, one for two (2) days, one for two (2) days and one for one (1) day. Each Grade 1 Employee would be entitled to the higher duties allowance.</p><p><strong>37.3</strong> The Relieving Employee is entitled to have the higher duties allowance in this clause 37 paid whilst they are on any period of paid leave if:</p><p><strong>(a)</strong> they will be engaged in performing the duties of the Absent Employee/Vacant Position when they return to work from the paid leave; and</p><p><strong>(b)</strong> the Employer is not paying another employee a higher duties allowance as a result of the Relieving Employee’s absence.</p><p><strong>37.4</strong> An Employee may refuse to be engaged to perform higher duties.</p><p><strong>37.5</strong> Different Payment to that in subclause 37.2</p><p><strong>(a)</strong> Where a Relieving Employee is in a profession at the top increment of their Grade/Level/Class outlined in Column A &amp; B, instead of the minimum rate specified in subclause 37.2(a)(i) or (b)(i), they will be paid not less than the rate applying to the classification outlined in Column C. Column A Column B Column C Employees Higher Duties Profession Substantive Classification Classification AHP 1: • Art Therapists • Cardiac Technologists (Cardiac Physiologists) • Dental Prosthetists • Exercise Physiologists • Health Information Managers (Medical Records Administrators) • Health Promotion Officers (Health Promotion Practitioners) • Medical Imaging Technologists (Radiographers) • Medical Librarians • Music Therapists Grade 2, Year 4 Grade 3, Year 2 • Nuclear Medicine Technologists • Occupational Therapists • Orthoptists • Orthotist/Prosthetists • Photography/Illustrator (Medical Photographer or Illustrator) • Physiotherapists • Play Therapists (Child Life Therapists) • Podiatrists • Recreation Therapists • Social Workers • Speech Pathologists Radiation Therapy Technologists (Radiation Therapists) Grade 2, Year 4 Grade 3, Year 2</p><p>Grade 1, Year 4 Grade 2, Year 2 Biomedical Technologist Grade 2, Year 5 Grade 3, Year 3 Grade 3, Year 4 Grade 4, Year 2 Child Psychotherapists Level 2, Year 5 Level 3, Year 2 Level 3, Year 3 Level 4, Year 2 Mechanical Officers Grade 1, Year 2 Grade 2, Year 2 Medical Laboratory Technician Grade 1, Year 8 Grade 2, Year 3 Renal Dialysis (Clinical Renal Physiologists)/Medical Technicians Grade 1, Year 6 Grade 2, Year 2</p><p>Research Technologists (Research Level B (2), SNR Level A (1), SNR Scientists) RESEARCH RESEARCH ASST 2 OFFR 3</p><p>Level B (2), SNR Level C (3), SNR RESEARCH OFFR 8 RESEARCH FELLOW 3 Grade 1, Year 4 Grade 2, Year 2 Technical Officer Grade 2, Year 5 Grade 3, Year 2 Grade 3, Year 4 Grade 4, Year 2 Class 1, Year 4 Class 2A, Year 4 Class 1, Year 4 Class 2AB, Year 3 Class 2A, Year 11 Class 2B, Year 5 Community Development Worker Class 2A, Year 11 Class 3, Year 2 Class 2AB, Year 11 Class 2B, Year 5 Class 2AB, Year 11 Class 3, Year 2 Class 2B, Year 7 Class 3, Year 4 Unqualified, Year 7 Class 1, Year 4 Class 1, Year 7 Class 2, Year 3 Class 2, Year 5 Class 3, Year 3 Welfare Worker Class 2A, Year 5 Class 3A, Year 5 Class 3, Year 3 Class 4, Year 2 Class 3A, Year 5 Class 4A, Year 5 Class 4, Year 3 Class 4A, Year 4 Class 1, Year 7 Class 2, Year 5 Class 2, Year 5 Class 2A, Year 2 Class 2, Year 5 Class 3, Year 3 Youth Worker Class 2A, Year 5 Class 3A, Year 5 Class 3, Year 3 Class 3A, Year 3 Class 3, Year 3 Class 4, Year 2</p><p>Note: the information in the above table is to give effect to the principle that an Employee engaged in performing higher duties is paid at a rate immediately above the rate of pay for their substantive position when engaged in performing higher duties in the above scenarios.</p><p>Plain language terms: acting up, HDA.</p>',26)])])}const m=a(r,[["render",o]]);export{g as __pageData,m as default};
